python -c "import json, pathlib, collections; p=pathlib.Path('docs/ocr_redesign/eval_line_transcription_surya_paddle_validation.json'); data=json.loads(p.read_text()); reports=data['file_reports'];
merge=[]; empty=[]; extra=[]; uncertain=[]
for r in reports:
    exp=len(r.get('expected_lines', [])); pred=len(r.get('predicted_lines', [])); seg=r.get('segmentation_line_count', 0); unc=r.get('uncertainty_count', 0)
    if pred == 0 and exp > 0:
        empty.append(r['file_name'])
    if pred < exp and pred > 0:
        merge.append((r['file_name'], exp, pred, seg, round(r.get('sequence_similarity', 0.0), 3)))
    if pred > exp:
        extra.append((r['file_name'], exp, pred, seg, round(r.get('sequence_similarity', 0.0), 3)))
    if unc > 0:
        uncertain.append((r['file_name'], unc, r.get('fallback_invocations', 0)))
print('empty_predictions', len(empty), empty[:10])
print('possible_merge_cases', len(merge), merge[:10])
print('possible_extra_split_or_noise_cases', len(extra), extra[:10])
print('uncertain_cases', len(uncertain), uncertain[:15])"

